input.old_string:
.printonet-feature-split__body {
  background: var(--printonet-surface);
  align-items: start;
  padding: clamp(1.3rem, 3vw, 2.4rem);
  display: grid;
  align-content: center;
  gap: 0.65rem;
}

input.new_string:
.printonet-feature-split__body {
  background: var(--printonet-surface);
  align-items: start;
  padding: clamp(1.3rem, 3vw, 2.4rem);
  display: grid;
  align-content: center;
  gap: 0.65rem;
  justify-items: start;
}

.printonet-feature-split__body h2,
.printonet-feature-split__body p {
  width: 100%;
  max-width: 48ch;
}

.printonet-feature-split__body .printonet-pill,
.printonet-feature-split__body .printonet-btn {
  width: fit-content;
  max-width: 100%;
  justify-self: start;
}

.printonet-feature-split--intro {
  min-height: 240px;
  height: 240px;
  grid-template-rows: 240px;
}

.printonet-feature-split--intro .printonet-feature-split__media,
.printonet-feature-split--intro .printonet-feature-split__body {
  height: 240px;
}

.printonet-feature-split--intro .printonet-feature-split__body {
  gap: 0.4rem;
  padding: clamp(0.55rem, 1.2vw, 1rem);
}

.printonet-feature-split--intro .printonet-feature-split__body h2 {
  font-size: clamp(1.1rem, 2vw, 1.55rem);
  line-height: 1.12;
}

.printonet-feature-split--intro .printonet-feature-split__body p {
  font-size: 0.82rem;
  line-height: 1.35;
}
